```typescript
type Cell = [number, number];

const toKey = (x: number, y: number): string => `${x},${y}`;
const fromKey = (key: string): [number, number] => {
  const [x, y] = key.split(",").map(Number);
  return [x, y];
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(([x, y]) => toKey(x, y)));

  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveSet.has(toKey(x + dx, y + dy))) count++;
      }
    }
    return count;
  };

  const candidates = new Set<string>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.add(toKey(x + dx, y + dy));
      }
    }
  }

  const result: Cell[] = [];
  for (const key of candidates) {
    const [x, y] = fromKey(key);
    const neighbors = countNeighbors(x, y);
    const alive = liveSet.has(key);
    if ((alive && (neighbors === 2 || neighbors === 3)) ||
        (!alive && neighbors === 3)) {
      result.push([x, y]);
    }
  }

  return result;
}
```

This improves:
- Removes duplication of `${x},${y}` pattern (Rule 3)
- Makes code clearer with named functions (Rule 2)
- `fromKey` replaces inline split/map/Number with a clear name

Also I can simplify the survival condition. Instead of:
```
(alive && (neighbors === 2 || neighbors === 3)) || (!alive && neighbors === 3)
```

This is equivalent to:
```
neighbors === 3 || (alive && neighbors === 2)
```

Because if neighbors === 3, both alive and dead cells survive/are born. If neighbors === 2, only alive cells survive.

Let me apply both refactorings.

